#include <stdio.h>

// Color Palet Code
int main()
{
    int i, j;
    for (i = 0; i < 8; i++)
    {
        for (j = 0; j < 8; j++)
        {
            printf("\033[1;%d;%dm", 30 + i, 40 + j);
            printf("Color %d-%d", i, j);
            printf("\033[0m\t");
        }
        printf("\n");
    }
}
